#include <iostream>
#include <string>
#include <vector>

class Student {
private:
    std::string studentName;
    int studentID;
    char grade;

public:
    Student() {
        studentName = "Unknown";
        studentID = 0;
        grade = 'U';
    }

    Student(std::string name, int id, char g) {
        studentName = name;
        studentID = id;
        grade = g;
    }

    std::string getStudentName() {
        return studentName;
    }

    int getStudentID() {
        return studentID;
    }

    char getGrade() {
        return grade;
    }

    void printStudentDetails() {
        std::cout << "Name: " << studentName << std::endl;
        std::cout << "ID: " << studentID << std::endl;
        std::cout << "Grade: " << grade << std::endl;
    }
};

int main() {
    Student student1;
    Student student2("Alice Smith", 1001, 'A');
    Student student3("Bob Johnson", 2002, 'B');
    Student student4("Charlie Brown", -5, 'X'); // Demonstrates robustness issue

    std::cout << "Student 1:\n";
    student1.printStudentDetails();
    std::cout << "--------------------\n";

    std::cout << "Student 2:\n";
    student2.printStudentDetails();
    std::cout << "--------------------\n";

    std::cout << "Student 3:\n";
    student3.printStudentDetails();
    std::cout << "--------------------\n";

    std::cout << "Student 4 (Robustness Issue - Invalid Data):\n";
    student4.printStudentDetails();
    std::cout << "--------------------\n";

    return 0;
}
